            @as(i32, @bitCast(@as(u32, 0x80087467)));
        const ws = std.posix.winsize{
            .col = @intCast(@min(cols, 0xFFFF)),
            .row = @intCast(@min(rows, 0xFFFF)),
            .xpixel = 0,
            .ypixel = 0,
        };
        _ = std.c.ioctl(self.pty_fd, TIOCSWINSZ, @intFromPtr(&ws));
    }

